import json
import math
import os
import struct
import sys

EPS = 1e-9
ROUND_DECIMALS = 6


def sub(a, b):
    return (a[0]-b[0], a[1]-b[1], a[2]-b[2])


def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]


def cross(a, b):
    return (
        a[1]*b[2] - a[2]*b[1],
        a[2]*b[0] - a[0]*b[2],
        a[0]*b[1] - a[1]*b[0],
    )


def mag(v):
    return math.sqrt(dot(v, v))


def normalize(v):
    m = mag(v)
    if m < EPS:
        return (0.0, 0.0, 0.0)
    return (v[0]/m, v[1]/m, v[2]/m)


def tri_area(v1, v2, v3):
    return 0.5 * mag(cross(sub(v2, v1), sub(v3, v1)))


def parse_ascii_stl_text(text):
    triangles = []
    issues = []
    lines = text.splitlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                n = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                issues.append(f'Malformed facet normal at line {i+1}')
                i += 1
                continue
            i += 1
            if i >= len(lines) or lines[i].strip() != 'outer loop':
                issues.append(f'Missing outer loop at line {i+1}')
                continue
            i += 1
            verts = []
            for _ in range(3):
                if i >= len(lines):
                    break
                vline = lines[i].strip()
                parts = vline.split()
                if len(parts) >= 4 and parts[0] == 'vertex':
                    try:
                        verts.append((float(parts[1]), float(parts[2]), float(parts[3])))
                    except Exception:
                        issues.append(f'Malformed vertex at line {i+1}')
                else:
                    issues.append(f'Malformed vertex at line {i+1}')
                i += 1
            if i >= len(lines) or lines[i].strip() != 'endloop':
                issues.append(f'Missing endloop near line {i+1}')
            else:
                i += 1
            if i >= len(lines) or lines[i].strip() != 'endfacet':
                issues.append(f'Missing endfacet near line {i+1}')
            else:
                i += 1
            if len(verts) == 3:
                triangles.append((n, verts))
            else:
                issues.append(f'Incomplete triangle near line {i+1}')
            continue
        i += 1
    return triangles, issues


def detect_binary_stl(data):
    if len(data) < 84:
        return False
    count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + count * 50
    if expected != len(data):
        return False
    try:
        header = data[:80].decode('ascii', errors='ignore').strip().lower()
    except Exception:
        header = ''
    return True if expected == len(data) else (not header.startswith('solid'))


def parse_binary_stl(data):
    triangles = []
    issues = []
    if len(data) < 84:
        return triangles, ['Binary STL too short']
    count = struct.unpack('<I', data[80:84])[0]
    expected = 84 + count * 50
    if expected != len(data):
        issues.append('Binary STL size does not match triangle count in header')
        count = min(count, max(0, (len(data)-84)//50))
    off = 84
    for idx in range(count):
        chunk = data[off:off+50]
        if len(chunk) < 50:
            issues.append(f'Triangle record {idx} truncated')
            break
        vals = struct.unpack('<12fH', chunk)
        n = (vals[0], vals[1], vals[2])
        verts = [
            (vals[3], vals[4], vals[5]),
            (vals[6], vals[7], vals[8]),
            (vals[9], vals[10], vals[11]),
        ]
        triangles.append((n, verts))
        off += 50
    return triangles, issues


def load_stl(path):
    with open(path, 'rb') as f:
        data = f.read()
    if detect_binary_stl(data):
        tris, issues = parse_binary_stl(data)
        return 'binary', tris, issues
    text = data.decode('utf-8', errors='replace')
    tris, issues = parse_ascii_stl_text(text)
    return 'ascii', tris, issues


def validate_triangles(triangles, parse_issues):
    issues = list(parse_issues)
    if not triangles:
        issues.append('No valid faces found')
        return {
            'valid': False,
            'suitable_for_manufacturing': False,
            'triangle_count': 0,
            'surface_area': 0.0,
            'volume': 0.0,
            'issues': issues,
        }

    edge_counts = {}
    oriented_edges = {}
    total_area = 0.0
    signed_volume = 0.0
    degenerate_count = 0
    normal_mismatch_count = 0

    for declared_normal, verts in triangles:
        v1, v2, v3 = verts
        a = tri_area(v1, v2, v3)
        total_area += a
        c = cross(sub(v2, v1), sub(v3, v1))
        cm = mag(c)
        if cm < EPS:
            degenerate_count += 1
        else:
            wn = normalize(c)
            dn = normalize(declared_normal)
            if mag(dn) >= EPS and dot(dn, wn) < 0.0:
                normal_mismatch_count += 1
        signed_volume += dot(v1, cross(v2, v3)) / 6.0

        rv = [tuple(round(x, ROUND_DECIMALS) for x in p) for p in verts]
        cyc = [(rv[0], rv[1]), (rv[1], rv[2]), (rv[2], rv[0])]
        for e in cyc:
            key = tuple(sorted(e))
            edge_counts[key] = edge_counts.get(key, 0) + 1
            oriented_edges[e] = oriented_edges.get(e, 0) + 1

    open_edges = sum(1 for c in edge_counts.values() if c == 1)
    nonmanifold_edges = sum(1 for c in edge_counts.values() if c > 2)
    same_dir_edges = 0
    for (a, b), cnt in oriented_edges.items():
        opp = oriented_edges.get((b, a), 0)
        if cnt > opp:
            same_dir_edges += cnt - opp

    if degenerate_count:
        issues.append(f'Mesh has {degenerate_count} degenerate triangle(s)')
    if open_edges:
        issues.append(f'Mesh has {open_edges} open edge(s) — not a closed solid')
    if nonmanifold_edges:
        issues.append(f'Mesh has {nonmanifold_edges} non-manifold edge(s)')
    if normal_mismatch_count:
        issues.append(f'{normal_mismatch_count} face normal(s) disagree with winding order')
    if total_area < EPS:
        issues.append('Surface area is zero')
    if abs(signed_volume) < EPS:
        issues.append('Enclosed volume is zero or numerically negligible')

    suitable = not any([
        degenerate_count,
        open_edges,
        nonmanifold_edges,
        total_area < EPS,
        abs(signed_volume) < EPS,
    ])

    return {
        'valid': len(issues) == 0,
        'suitable_for_manufacturing': suitable,
        'triangle_count': len(triangles),
        'surface_area': round(total_area, 6),
        'volume': round(abs(signed_volume), 6),
        'issues': issues,
    }


def validate_file(path):
    fmt, tris, parse_issues = load_stl(path)
    result = validate_triangles(tris, parse_issues)
    result['format'] = fmt
    result['file'] = path
    return result


if __name__ == '__main__':
    paths = sys.argv[1:]
    if not paths:
        print(json.dumps({'error': 'usage: stl_validate_batch_cli.py <file1.stl> [file2.stl ...]'}))
        sys.exit(1)
    print(json.dumps([validate_file(p) for p in paths], indent=2))

